% ============================================================
% SECTION 2: RULES (predefined — do NOT modify)
% ============================================================

%--- Passing criteria ------------------------------------------
passes_cie(CIE)            :- CIE >= 18.
passes_ese(ESE)            :- ESE >= 24.
passes_subject(CIE, ESE)   :- passes_cie(CIE), passes_ese(ESE).
fails_subject(CIE, ESE)    :- \+ passes_subject(CIE, ESE).

%--- Grade points (10-point scale) ----------------------------
grade_points(Total, 10) :- Total >= 91, !.
grade_points(Total,  9) :- Total >= 81, !.
grade_points(Total,  8) :- Total >= 71, !.
grade_points(Total,  7) :- Total >= 61, !.
grade_points(Total,  6) :- Total >= 55, !.
grade_points(Total,  5) :- Total >= 50, !.
grade_points(Total,  4) :- Total >= 40, !.
grade_points(_,       0).

%--- Number of backlogs (failed subjects) ---------------------
number_of_backlogs(RollNo, Semester, Count) :-
    findall(SubId,
        ( marks(RollNo, SubId, Semester, CIE, ESE, _, _),
          fails_subject(CIE, ESE) ),
        FailedList),
    length(FailedList, Count).

%--- Total credits earned (sum of credits_earned from marks) ---
total_credits(RollNo, Semester, TotalCredits) :-
    findall(Cr,
        marks(RollNo, _, Semester, _, _, _, Cr),
        CreditsList),
    sumlist(CreditsList, TotalCredits).

%--- SGPA calculation -----------------------------------------
% Weighted grade points summed over ALL subjects in semester
sgpa(RollNo, Semester, SGPA) :-
    findall(WGP,
        ( marks(RollNo, SubId, Semester, _CIE, _ESE, Total, _),
          subject(SubId, _, Cr),
          grade_points(Total, GP),
          WGP is GP * Cr ),
        WGPList),
    WGPList \= [],
    sumlist(WGPList, TotalWGP),
    findall(Cr,
        ( marks(RollNo, SubId, Semester, _, _, _, _),
          subject(SubId, _, Cr) ),
        AllCredits),
    sumlist(AllCredits, TotalCr),
    TotalCr > 0,
    SGPA is TotalWGP / TotalCr.

%--- Grace marks calculation ----------------------------------
% Grace only if exactly 1 subject failed AND marks needed <= 6
grace_used(RollNo, Semester, Grace) :-
    number_of_backlogs(RollNo, Semester, Count),
    ( Count =:= 1 ->
        findall(cie-CIE + ese-ESE,
            ( marks(RollNo, _, Semester, CIE, ESE, _, _),
              fails_subject(CIE, ESE) ),
            [cie-FCIe + ese-FEse]),
        ( \+ passes_ese(FEse) ->
            Needed is 24 - FEse
        ;
            Needed is 18 - FCIe
        ),
        ( Needed =< 6 -> Grace = Needed ; Grace = 0 )
    ;
        Grace = 0
    ).

%--- Result status --------------------------------------------
result_status(RollNo, Semester, Status) :-
    number_of_backlogs(RollNo, Semester, Count),
    grace_used(RollNo, Semester, Grace),
    ( Count =:= 0 ->
        Status = 'PASS'
    ; Count =:= 1, Grace > 0 ->
        Status = 'PASS (Grace)'
    ; Count =:= 1 ->
        Status = 'ATKT'
    ;
        Status = 'FAIL'
    ).

%--- Total credits for ALL subjects in a semester -------------
total_credits_all(RollNo, Semester, TotalCr) :-
    findall(Cr,
        ( marks(RollNo, SubId, Semester, _, _, _, _),
          subject(SubId, _, Cr) ),
        CrList),
    sumlist(CrList, TotalCr).

%--- Weighted sum helper for CGPA -----------------------------
sum_weighted([], WSum, CrSum, WSum, CrSum).
sum_weighted([SGPA * Cr | Rest], WAcc, CAcc, WSum, CrSum) :-
    WAcc1 is WAcc + SGPA * Cr,
    CAcc1 is CAcc + Cr,
    sum_weighted(Rest, WAcc1, CAcc1, WSum, CrSum).

%--- CGPA (cumulative across all semesters) -------------------
cgpa(RollNo, CGPA) :-
    findall(Sem, marks(RollNo, _, Sem, _, _, _, _), RawSems),
    sort(RawSems, Semesters),
    Semesters \= [],
    findall(SGPA_Val * TotalCr,
        ( member(S, Semesters),
          sgpa(RollNo, S, SGPA_Val),
          total_credits_all(RollNo, S, TotalCr),
          TotalCr > 0 ),
        Pairs),
    Pairs \= [],
    sum_weighted(Pairs, 0, 0, WSum, CrSum),
    CrSum > 0,
    CGPA is WSum / CrSum.

%--- Next year eligibility ------------------------------------
% Criteria (BOTH must be met for the current year):
%   1. Total backlogs across BOTH semesters of the year <= 3
%   2. Total credits earned across BOTH semesters >= 34 (out of 46)
% The year's semesters: OddSem = Year*2-1, EvenSem = Year*2
next_year_eligible(RollNo, TotalBacklogs, TotalCreditsEarned, MinCredits, Eligible) :-
    student(RollNo, _, _, _, Year, _),
    OddSem is Year * 2 - 1,
    EvenSem is Year * 2,
    MinCredits = 34,
    findall(SubId-S,
        ( member(S, [OddSem, EvenSem]),
          marks(RollNo, SubId, S, CIE, ESE, _, _),
          fails_subject(CIE, ESE) ),
        FailedPairs),
    length(FailedPairs, TotalBacklogs),
    findall(Cr,
        ( member(S, [OddSem, EvenSem]),
          marks(RollNo, _, S, _, _, _, Cr) ),
        AllCr),
    sumlist(AllCr, TotalCreditsEarned),
    ( TotalBacklogs =< 3, TotalCreditsEarned >= MinCredits ->
        Eligible = 'YES'
    ;
        Eligible = 'NO'
    ).
